INSERT OR REPLACE INTO "products" ("id","name","type","status","external_references","created_at","updated_at","description","slug","brand","categories","tags","options","default_variant_id","fulfillment_type","tax_category","primary_image","media","seo","rating","related_products","extensions") VALUES('prod_beauteas_stainless_steel_water_or_tea_bottle','BeauTeas 22oz Insulated Steel Water or Tea Bottle','Drinkware','archived','{"shopify_id":"6905839288487"}','2021-07-14T09:37:23-06:00','2026-06-29T23:10:36.938Z','{"en":"This 22-ounce, double-walled stainless steel water bottle is perfect for your daily outings. It will keep your BeauTeas tea hot or cold for hours. It also features an odor- and leak-proof cap. Throw it in your car''s cup holder on your way to work, take it with you on hikes, or toss it in your bag for any time you get thirsty.\n\n• High-grade stainless steel\n• 17 oz (500 ml)\n• Dimensions: 10.6″ × 2.9″\n• Vacuum flask\n• Double-wall construction\n• Odorless and leak-proof cap\n• Insulated for hot and cold liquids (keeps the liquid hot for 12h or cold for 48h)\n• Hand-wash only (dishwasher not recommended due to vacuum seal)"}','beauteas-stainless-steel-water-or-tea-bottle','BeauTeas.com','["cat_drinkware"]',NULL,'[{"id":"title","name":"Title","type":"select","values":[{"id":"default-title","value":"Default Title"}]}]','variant_beauteas_stainless_steel_water_or_tea_bottle_634473210798','physical','food','{"url":"products/beauteas-stainless-steel-water-or-tea-bottle.jpg","alt_text":"BeauTeas 22oz Insulated Steel Water or Tea Bottle"}','[{"url":"products/beauteas-stainless-steel-water-or-tea-bottle.jpg","alt_text":"BeauTeas 22oz Insulated Steel Water or Tea Bottle"},{"url":"products/beauteas-stainless-steel-water-or-tea-bottle-2.jpg","alt_text":"BeauTeas 22oz Insulated Steel Water or Tea Bottle"},{"url":"products/beauteas-stainless-steel-water-or-tea-bottle-3.jpg","alt_text":"BeauTeas 22oz Insulated Steel Water or Tea Bottle"},{"url":"products/beautea