INSERT OR REPLACE INTO "products" ("id","name","type","status","external_references","created_at","updated_at","description","slug","brand","categories","tags","options","default_variant_id","fulfillment_type","tax_category","primary_image","media","seo","rating","related_products","extensions") VALUES('prod_beauteas_white_glossy_mug','BeauTeas White Glossy Tea Mug','Mugs','archived','{"shopify_id":"6905811566759"}','2021-07-14T09:31:10-06:00','2026-06-29T23:10:36.938Z','{"en":"Whether you''re drinking your tea in the morning, at work, or in bed – this mug''s for you! It''s sturdy and glossy and safe in the microwave and dishwasher.\n\n• Ceramic Tea Mug\n• 11 oz mug dimensions: 3.85″ tall, 3.35″ in diameter\n• 15 oz mug dimensions: 4.7″ tall, 3.35″ in diameter\n• Dishwasher and microwave safe\n• Lead and BPA Free"}','beauteas-white-glossy-mug','BeauTeas.com','["cat_drinkware"]',NULL,'[{"id":"size","name":"Size","type":"select","values":[{"id":"11oz","value":"11oz"},{"id":"15oz","value":"15oz"}]}]','variant_beauteas_white_glossy_mug_97549621320','physical','food','{"url":"products/beauteas-white-glossy-mug.jpg","alt_text":"BeauTeas White Glossy Tea Mug"}','[{"url":"products/beauteas-white-glossy-mug.jpg","alt_text":"BeauTeas White Glossy Tea Mug"},{"url":"products/beauteas-white-glossy-mug-2.jpg","alt_text":"BeauTeas White Glossy Tea Mug"},{"url":"products/beauteas-white-glossy-mug-3.jpg","alt_text":"BeauTeas White Glossy Tea Mug"},{"url":"products/beauteas-white-glossy-mug-4.jpg","alt_text":"BeauTeas White Glossy Tea Mug"},{"url":"products/beauteas-white-glossy-mug-5.jpg","alt_text":"BeauTeas White Glossy Tea Mug"},{"url":"products/beauteas-white-glossy-mug-6.jpg","alt_text":"BeauTeas White Glossy Tea Mug"},{"url":"products/beauteas-white-glossy-mug-7.jpg","alt_text":"BeauTeas White Glossy Tea Mug"}]',NULL,NULL,NULL,'{"vendor":"BeauTeas.com","product_type":"Mugs"}');
INSERT OR REPLACE INTO "products" ("id","name","type","status","external_references","created_at","updated_at","description","slug","brand","categories","tags","options","default_variant_id","fulfillment_type","tax_category","primary_image","media","seo","rating","related_products","extensions") VALUES('prod_clearly_calendula_afternoon','Clearly Calendula Afternoon','Tea Bags','active','{"shopify_id":"6648001003687"}','2021-04-17T12:30:33-06:00','2026-07-01 19:58:12','{"en":"Power through your afternoon with our refreshing organic green tea blend designed for skin health and sustained energy. This unique blend combines premium Dragonwell and Sencha green teas with lemon verbena, spearmint, peppermint, and calendula petals. Perfect hot or iced, at work, school, or the gym. The calendula fights bacteria and stimulates collagen, spearmint provides anti-inflammatory benefits, and lemon verbena combats acne-causing bacteria. Enjoy smooth, long-lasting energy while supporting your skin health journey. 100% USDA Certified Organic."}','clearly-calendula-afternoon','BeauTeas.com','["cat_frontpage","cat_clearly_calendula"]',NULL,'[{"id":"size","name":"Size","type":"select","values":[{"id":"one-box-10-tea-bags","value":"One box (10 tea bags)"},{"id":"three-boxes-30-tea-bags","value":"Three boxes (30 tea bags)"}]}]','variant_clearly_calendula_afternoon_btcca1','physical','food','{"url":"products/clearly-calendula-afternoon.jpg","alt_text":"Clearly Calendula Afternoon"}','[{"url":"products/clearly-calendula-afternoon.jpg","alt_text":"Clearly Calendula Afternoon"},{"url":"products/clearly-calendula-afternoon-2.jpg","alt_text":"Clearly Calendula Afternoon"},{"url":"products/clearly-calendula-afternoon-3.jpg","alt_text":"Clearly Calendula Afternoon"},{"url":"products/clearly-calendula-afternoon-4.jpg","alt_text":"Clearly Calendula Afternoon"},{"url":"products/clearly-calendula-afternoon-5.jpg","alt_text":"Clearly Calendula Afternoon"},{"url":"products/clearly-calendula-afternoon-6.jpg","alt_text":"Clearly Calendula Afternoon"},{"url":"products/clearly-calendula-afternoon-7.jpg","alt_text":"Clearly Calendula Afternoon"}]',NULL,NULL,NULL,'{"vendor":"BeauTeas.com","product_type":"Tea Bags","ingredients":"Organic Dragonwell Green Tea, Organic Sencha Green Tea, organic lemon verbena, organic spearmint, organic peppermint, organic calendula petals","caffeine":"caffeinated","servings":"10 tea bags per box","benefits":["Fights acne-causing bacteria","Heals acne and skin damage","Aids weight loss","Reduces hormone swings","Smooth long-lasting energy","Rich in antioxidants"],"certifications":["USDA Organic"],"brewing":{"temp":"175°F","time":"2-3 minutes"}}');
INSERT OR REPLACE INTO "products" ("id","name","type","status","external_references","created_at","updated_at","description","slug","brand","categories","tags","options","default_variant_id","fulfillment_type","tax_category","primary_image","media","seo","rating","related_products","extensions") VALUES('prod_clearly_calendula_evening','Clearly Calendula Evening','Tea Bags','active','{"shopify_id":"6648004804775"}','2021-04-17T12:32:25-06:00','2026-07-01 19:58:13','{"en":"Wind down your day with our soothing caffeine-free herbal blend designed for evening relaxation and overnight skin repair. This calming tea combines organic chamomile, rooibos, spearmint, peppermint, and calendula petals. Chamomile promotes relaxation, calendula heals and fights bacteria, spearmint controls hormone-based acne, peppermint reduces oil production, and rooibos delivers antioxidants plus natural alpha hydroxy acids (AHA) for gentle skin renewal. Enjoy before bed for a restful sleep while your skin repairs. 100% USDA Certified Organic and completely caffeine-free."}','clearly-calendula-evening','BeauTeas.com','["cat_frontpage","cat_clearly_calendula"]',NULL,'[{"id":"size","name":"Size","type":"select","values":[{"id":"one-box-10-tea-bags","value":"One box (10 tea bags)"},{"id":"three-boxes-30-tea-bags","value":"Three boxes (30 tea bags)"}]}]','variant_clearly_calendula_evening_btcce1','physical','food','{"url":"products/clearly-calendula-evening.jpg","alt_text":"Clearly Calendula Evening"}','[{"url":"products/clearly-calendula-evening.jpg","alt_text":"Clearly Calendula Evening"},{"url":"products/clearly-calendula-evening-2.jpg","alt_text":"Clearly Calendula Evening"},{"url":"products/clearly-calendula-evening-3.jpg","alt_text":"Clearly Calendula Evening"},{"url":"products/clearly-calendula-evening-4.jpg","alt_text":"Clearly Calendula Evening"},{"url":"products/clearly-calendula-evening-5.jpg","alt_text":"Clearly Calendula Evening"},{"url":"products/clearly-calendula-evening-6.jpg","alt_text":"Clearly Calendula Evening"},{"url":"products/clearly-calendula-evening-7.jpg","alt_text":"Clearly Calendula Evening"}]',NULL,NULL,NULL,'{"vendor":"BeauTeas.com","product_type":"Tea Bags","ingredients":"Organic chamomile, organic rooibos, organic spearmint, organic peppermint, organic calendula petals","caffeine":"caffeine-free","servings":"10 tea bags per box","benefits":["Fights acne-causing bacteria","Heals acne and skin damage","Contains alpha hydroxy acid (AHA)","Reduces hormone-based acne","Soothing and calming","Rich in antioxidants"],"certifications":["USDA Organic"],"brewing":{"temp":"212°F","time":"5-7 minutes"}}');
INSERT OR REPLACE INTO "products" ("id","name","type","status","external_references","created_at","updated_at","description","slug","brand","categories","tags","options","default_variant_id","fulfillment_type","tax_category","primary_image","media","seo","rating","related_products","extensions") VALUES('prod_clearly_calendula_full_package','Clearly Calendula Mega Month','Tea Bags','active','{"shopify_id":"6652115910823"}','2021-04-19T16:23:14-06:00','2026-07-01 19:58:14','{"en":"Discover the complete Clearly Calendula collection with our sample pack featuring one box (10 tea bags) each of Morning (black tea), Afternoon (green tea), and Evening (herbal tea). Experience the full day of skincare tea benefits - energize in the morning, maintain focus in the afternoon, and relax in the evening while your skin heals and rejuvenates around the clock. All teas are 100% USDA Certified Organic with compostable tea bags made from sugarcane. The perfect introduction to beauty from within or a thoughtful gift for tea and skincare enthusiasts."}','clearly-calendula-full-package','BeauTeas.com','["cat_clearly_calendula"]',NULL,'[{"id":"title","name":"Title","type":"select","values":[{"id":"default-title","value":"Default Title"}]}]','variant_clearly_calendula_full_package_btccfp','physical','food','{"url":"products/clearly-calendula-full-package.jpg","alt_text":"Clearly Calendula Mega Month"}','[{"url":"products/clearly-calendula-full-package.jpg","alt_text":"Clearly Calendula Mega Month"},{"url":"products/clearly-calendula-full-package-2.jpg","alt_text":"Clearly Calendula Mega Month"},{"url":"products/clearly-calendula-full-package-3.jpg","alt_text":"Clearly Calendula Mega Month"},{"url":"products/clearly-calendula-full-package-4.jpg","alt_text":"Clearly Calendula Mega Month"}]',NULL,NULL,NULL,'{"vendor":"BeauTeas.com","product_type":"Tea Bags","benefits":["100% USDA Certified Organic","Fights and heals acne","Increases collagen production","Rich in antioxidants","Hydrating and f