INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(4,'About Us','about-us',replace('<div style="display: none;"></div>\n<div style="display: none;"></div>\n<div style="display: none;"></div>\n<p>BeauTeas was created by blending a love of the beauty community with a love for nourishing the body (and soul) with all-natural organic plant-based goodness.  We believe that the best way to improve how your body looks and feels is through clean plant-based nutrition.  By blending organic flowers and powerful, healing herbs to make tasty hydrating teas, our products make it easy for anyone to improve their skin and appearance without slathering on harsh chemicals.</p>\n<p>Our motto is Build Your Beauty From Within.  Trust us, we still love makeup, moisturizers, serums, and sunscreens!  But regularly drinking our teas will give you healthy long term improvements that you''ll appreciate every time you look in the mirror.</p>\n<p>Our founder, Dana, has been passionate about beauty and the beauty community since she was in her early teens.  She may have more palettes and brushes than she cares to admit:) After getting her culinary degree, working in Colorado''s progressive food industry, and seeing what a difference  clean, organic, all-natural nutrition can make, she was inspired to create BeauTeas.</p>\n<p>Teas are the perfect way to bring the power of plants into our lives. Our BeauTeas blends are loaded with anti-oxidants, anti-inflammatories, Alpha Hydroxy Acids, catechins, and many more valuable natural compounds.  When you drink our tea, your body absorbs the good nutrients more effectively than nutrients it gets from vitamins or topical application.  Drinking tea also helps you stay hydrated, which is super important for everything from how your skin and hair look, to your energy levels, to the health of your organs including your brain!  </p>\n<p>So join our BeauTeas Community, sip, relax, and enjoy feeling better and looking better. Build Your Beauty From Within!</p>\n<p> </p>\n<div style="text-align: center;"><img src="https://cdn.shopify.com/s/files/1/0554/7288/1831/files/85A6329_e90889c6-2175-4c97-ab75-96eac46c1115_1024x1024.jpg?v=1626361061" alt="" style="float: none;"></div>','\n',char(10)),NULL,'About Us','BeauTeas was created by blending a love of the beauty community with a love for nourishing the body (and soul) with all-natural organic plant-based goodness....',NULL,'published',1625798862,'default',NULL,0,1625798862,1626361096,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(5,'Brewing Directions','brewing-directions',replace('<div style="display: none;"></div>\n<p>Brewing your tea correctly will help ensure that it tastes delicious and that you are getting the most benefits from the organic herbs and flowers in our tea blends.  Don''t stress out over the precise temperatures, or freak out if you let it steep a little too long, these are just guidelines to help you get the most out of your tea.</p>\n<p> </p>\n<h2>Black Teas</h2>\n<p>For Black teas, like our Clearly Calendula Morning, which is an Earl Grey based tea, we recommend using water that is between 205 and 212 degrees Fahrenheit.</p>\n<p>It''s best to boil water, and then let it cool for 30 seconds or so before pouring it into your tea cup.  But you can use boiling water if you''re in a rush:) </p>\n<p>Add the tea bag to the hot water in the cup, and let it steep for 3-5 minutes, before removing the tea bag.  If you let it steep too long the tea can taste too strong and slightly bitter (it''s still safe to drink).  </p>\n<p> </p>\n<p> </p>\n<h2>Green Teas</h2>\n<meta charset="UTF-8">\n<p>For Green teas, like our Clearly Calendula Afternoon, which is a Green tea, we recommend using water that is around 175 degrees Fahrenheit.</p>\n<p>It''s best to boil water, and then let it cool for 3 minutes or so before pouring it into your tea cup.  Or you can get a kettle which allows you to set the target temperature for 175 degrees.</p>\n<p>Add the tea bag to the hot water in the cup, and let it steep for 2-4 minutes, before removing the tea bag.  If you let it steep too long the tea can taste too strong and slightly bitter (it''s still safe to drink).  </p>\n<p> </p>\n<h2>Herbal Teas</h2>\n<meta charset="UTF-8">\n<p>For Herbal teas, like our Clearly Calendula Evening, which is a herbal tea, we recommend using water that is around 212 degrees Fahrenheit.</p>\n<p>It''s best to boil water, and immediately pour it into your tea cup.  </p>\n<p>Add the tea bag to the hot water in the cup, and let it steep for at least 5 minutes, you don''t have to remove the tea bag.  Generally letting herbal teas steep longer can make them taste a little stronger, but they won''t become bitter or unpleasant to drink.  </p>\n<p> </p>\n<p> </p>\n<h2>Iced Teas</h2>\n<p>Iced tea can be a super refreshing way to drink your tea, especially in warm weather, or at the gym.  Luckily it''s easy to make!  You can easily brew up a large amount of tea, using multiple tea bags in a pitcher.  Generally you will want one bag for every 8-16 oz of water, depending on how strong you like it.</p>\n<p>Black teas must be hot brewed, using the directions above, and then chilled.  It''s usually best to let the hot tea cool to room temperature on your counter, and then move it into the refrigerator.  </p>\n<p>For Green and Herbal teas, you can hot brew, and then chill like with Black teas. However you can also cold brew these teas as well, which might be easier.  Cold brewing is basically just adding your tea bags to cold water, and letting it steep for at least two hours and up to several days.</p>\n<p>You can do this inside a water bottle, mason jar, or large pitcher.  You can drink it with ice, or just chilled from the fridge.  </p>\n<p>Play around with amounts and timing to figure out what you like best!  </p>\n<p> </p>\n<p><img src="https://cdn.shopify.com/s/files/1/0554/7288/1831/files/85A6494_1024x1024.jpg?v=1625358797" alt=""></p>','\n',char(10)),NULL,'Brewing Directions','Brewing your tea correctly will help ensure that it tastes delicious and that you are getting the most benefits from the organic herbs and flowers in our tea...',NULL,'published',1624576251,'default',NULL,0,1624576251,1625358812,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(6,'CCPA Compliance','ccpa-compliance',replace(replace('<style>\n    #form-ccpa-edit-account-request,\n    #form-ccpa-data-account-request,\n    #form-ccpa-personal-data-report-request,\n    #form-ccpa-delete-account-request ,\n    #form-ccpa-do-not-sell-request {\n        display: none;\n    }\n    #ccpa_page button {\n      background-color: transparent;\n      border: 0;\n      border-bottom: 1px solid black;\n      padding: 0px;\n    }\n\n    /* Modal background */\n    #data-verification-background {\n      display: none;\n      position: fixed;\n      z-index: 1;\n      padding-top: calc(50vh - 83px);\n      left: 0;\n      top: 0;\n      width: 100%;\n      height: 100%;\n      overflow: auto;\n      background-color: rgb(0,0,0);\n      background-color: rgba(0,0,0,0.4);\n      opacity: unset;\n      z-index: 9999;\n    }\n    /* Modal Content */\n    #data-verification-modal {\n      background-color: #fefefe;\n      margin: auto;\n      padding: 16px;\n      border: 1px solid #888;\n      width: 38%;\n    }\n    /* Modal Close Button */\n    .data-verification-close {\n      color: #aaaaaa;\n      float: right;\n      font-size: 28px;\n      font-weight: bold;\n      line-height: 17px;\n    }\n    .data-verification-close:hover,\n    .data-verification-close:focus {\n      color: #000;\n      text-decoration: none;\n      cursor: pointer;\n    }\n    /* Checkbox Text */\n    #data-verification-container p{\n      display: inline-block;\n      padding-left: 5px;\n      vertical-align: top;\n      width: calc(100% - 45px);\n      cursor: pointer;\n    }\n    #data-verification-container a, #data-verification-container a:hover{\n      text-decoration: underline!important;\n      color: #4285f4;\n    }\n    /* Checkbox Icon */\n    #data-verification-icon {\n      cursor: pointer;\n      position: relative;\n      margin: auto;\n      width: 18px;\n      height: 18px;\n      -webkit-tap-highlight-color: transparent;\n      transform: translate3d(0, 0, 0);\n      margin-top: 2px;\n    }\n    #data-verification-icon:before {\n      content: "";\n      position: absolute;\n      top: -7px;\n      left: -7px;\n      width: 32px;\n      height: 32px;\n      border-radius: 50%;\n      background: rgba(34,50,84,0.03);\n      opacity: 0;\n      transition: opacity 0.2s ease;\n    }\n    #data-verification-icon svg {\n      position: relative;\n      z-index: 1;\n      fill: none;\n      stroke-linecap: round;\n      stroke-linejoin: round;\n      stroke: #c8ccd4;\n      stroke-width: 1.5;\n      transform: translate3d(0, 0, 0);\n      transition: all 0.2s ease;\n    }\n    #data-verification-icon svg path {\n      stroke-dasharray: 60;\n      stroke-dashoffset: 0;\n    }\n    #data-verification-icon svg polyline {\n      stroke-dasharray: 22;\n      stroke-dashoffset: 66;\n    }\n    #data-verification-icon:hover:before {\n      opacity: 1;\n    }\n    #data-verification-container:hover #data-verification-icon svg {\n      stroke: #4285f4;\n    }\n    #data-verification-icon.clicked svg {\n      stroke: #4285f4;\n    }\n    #data-verification-icon.clicked svg path {\n      stroke-dashoffset: 60;\n      transition: all 0.3s linear;\n    }\n    #data-verification-icon.clicked svg polyline {\n      stroke-dashoffset: 42;\n      transition: all 0.2s linear;\n      transition-delay: 0.15s;\n    }\n\n    /* Modal changes on mobile resolution*/\n    @media only screen and (max-width: 600px) {\n      #data-verification-modal {\n        width: 90%;\n      }\n    }\n\n    /* Loading Element */\n    .loading {\n        display: none;\n        top:50vh;\n        left:50vw;\n        position:fixed;\n    }\n    .loading:not(:required):after {\n      content: '''';\n      display: block;\n      font-size: 10px;\n      width: 1em;\n      height: 1em;\n      margin-top: -0.5em;\n      -webkit-animation: spinner 1500ms infinite linear;\n      -moz-animation: spinner 1500ms infinite linear;\n      -ms-animation: spinner 1500ms infinite linear;\n      -o-animation: spinner 1500ms infinite linear;\n      animation: spinner 1500ms infinite linear;\n      border-radius: 0.5em;\n      -webkit-box-shadow: rgba(255,255,255, 1) 1.5em 0 0 0, rgba(255,255,255, 1) 1.1em 1.1em 0 0, rgba(255,255,255, 1) 0 1.5em 0 0, rgba(255,255,255, 1) -1.1em 1.1em 0 0, rgba(255,255,255, 1) -1.5em 0 0 0, rgba(255,255,255, 1) -1.1em -1.1em 0 0, rgba(255,255,255, 1) 0 -1.5em 0 0, rgba(255,255,255, 1) 1.1em -1.1em 0 0;\n      box-shadow: rgba(255,255,255, 1) 1.5em 0 0 0, rgba(255,255,255, 1) 1.1em 1.1em 0 0, rgba(255,255,255, 1) 0 1.5em 0 0, rgba(255,255,255, 1) -1.1em 1.1em 0 0, rgba(255,255,255, 1) -1.5em 0 0 0, rgba(255,255,255, 1) -1.1em -1.1em 0 0, rgba(255,255,255, 1) 0 -1.5em 0 0, rgba(255,255,255, 1) 1.1em -1.1em 0 0;\n    }\n\n    /* Animation */\n    @-webkit-keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n    @-moz-keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n    @-o-keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n    @keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n</style>\r\n<div id="ccpa_page" class="col-sm-12">\r\n    <div class="text-center">\r\n        The app used for assuring the GDPR/CCPA compliance of this site, collects your IP and the email address in order to process the data. For more check <a href="https://gdprcdn.b-cdn.net/pages/privacy_policy" target="_blank"> Privacy Policy</a><a>\r\n    </a>\n</div>\r\n    <h2>Data Rectification</h2>\r\n    <p>You can use the link below to update your account data if it is not accurate.</p>\r\n    <ul class="list-unstyled">\r\n        <li><button id="btn-ccpa-edit-account-request" aria-label="edit your account information" aria-controls="form-ccpa-edit-account-request" aria-expanded="false">Edit your account information</button></li>\r\n    </ul>\r\n    <div id="form-ccpa-edit-account-request">\r\n        <form>\r\n          <label for="form-ccpa-edit-account-request-email">Enter your email to confirm your identity</label>\r\n          <input type="email" name="email" id="form-ccpa-edit-account-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\r\n          <input type="submit" class="btn" value="Submit">\r\n        </form>\r\n    </div>\r\n    <h2>Data Portability</h2>\r\n    <p>You can use the links below to download all the data we store and use for a better experience in our store.</p>\r\n    <ul class="list-unstyled">\r\n        <li><button id="btn-ccpa-requests-request" aria-label="CCPA requests" aria-controls="form-ccpa-data-account-request" aria-expanded="false">CCPA requests</button></li>\r\n        <li><button id="btn-ccpa-personal-information-request" aria-label="personal information" aria-controls="form-ccpa-data-account-request" aria-expanded="false">Personal information</button></li>\r\n        <li><button id="btn-ccpa-orders-request" aria-label="orders" aria-controls="form-ccpa-data-account-request" aria-expanded="false">Orders</button></li>\r\n    </ul>\r\n    <div id="form-ccpa-data-account-request">\r\n        <form>\r\n            <label for="form-ccpa-data-account-request-email">Enter your email to confirm your identity</label>\r\n            <input type="email" name="email" id="form-ccpa-data-account-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\r\n            <input type="submit" class="btn" value="Submit">\r\n            <input type="hidden" name="request_type" value="">\r\n        </form>\r\n    </div>\r\n    <h2>Access to Personal Data</h2>\r\n    <p>You can use the link below to request a report which will contain all personal information that we store for you.</p>\r\n    <ul class="list-unstyled">\r\n      <li><button id="btn-ccpa-personal-data-report-request" aria-label="request a report" aria-controls="form-ccpa-personal-data-report-request" aria-expanded="false">Request a report</button></li>\r\n    </ul>\r\n    <div id="form-ccpa-personal-data-report-request">\r\n        <form>\r\n            <label for="form-ccpa-personal-data-report-request-email">Enter your email to confirm your identity</label>\r\n            <input type="email" name="email" id="form-ccpa-personal-data-report-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\r\n            <input type="submit" class="btn" value="Submit">\r\n        </form>\r\n    </div>\r\n       \r\n    <div id="do-not-sell">\r\n        <h2 style="margin-top: 55px;">Do not Sell My Personal Information</h2>\r\n        <p>You can submit a request to let us know that you do not agree for your personal information to be collected or sold.</p>\r\n        <ul class="list-unstyled">\r\n            <li><button id="btn-ccpa-do-not-sell-request" aria-label="request a report" aria-controls="form-ccpa-personal-data-report-request" aria-expanded="false">Do not sell my personal information</button></li>\r\n        </ul>\r\n        <div id="form-ccpa-do-not-sell-request">\r\n            <form>\r\n                <label for="form-ccpa-do-not-sell-request">Enter your email to confirm your identity</label>\r\n                <input type="email" name="email" id="form-ccpa-personal-data-report-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\r\n                <input type="submit" class="btn" value="Submit">\r\n            </form>\r\n        </div>\r\n    </div>\r\n    <h2>Right to be Forgotten</h2>\r\n    <p>Use this option if you want to remove your personal and other data from our store. Keep in mind that <strong>this process will delete your account, so you will no longer be able to access or use it anymore</strong>.</p>\r\n    <ul class="list-unstyled">\r\n      <li><button id="btn-ccpa-delete-account-request" aria-label="request personal data deletion" aria-controls="form-ccpa-delete-account-request" aria-expanded="false">Request personal data deletion</button></li>\r\n    </ul>\r\n    <div id="form-ccpa-delete-account-request">\r\n        <form>\r\n            <label for="form-ccpa-delete-account-request-email">Enter your email to confirm your identity</label>\r\n            <input type="email" name="email" id="form-ccpa-delete-account-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\r\n            <input type="submit" class="btn" value="Submit">\r\n        </form>\r\n    </div>\r\n</div>\r\n\r\n<script src="https://code.jquery.com/jquery-2.2.4.min.js" integrity="sha256-BbhdlvQf/xTY9gja0Dq3HiwQF8LaCRTXxZKRutelT44=" crossorigin="anonymous"></script>\r\n\r\n<script>\r\n    var ccpaSlideUpAll = function() {\r\n        $(''#form-ccpa-edit-account-request'').slideUp(100);\r\n        $(''#form-ccpa-data-account-request'').slideUp(100);\r\n        $(''#form-ccpa-personal-data-report-request'').slideUp(100);\r\n        $(''#form-ccpa-delete-account-request'').slideUp(100);\r\n        $(''#form-ccpa-do-not-sell-request'').slideUp(100);\r\n        $(''#ccpa_page button'').attr("aria-expanded", "false");\r\n    };\r\n\r\n    var email, type, consentGiven = false;\r\n    var verificationModalContent = ''<div id="data-verification-background"><div class="loading"></div><div id="data-verification-modal"><span class="data-verification-close">&times;</span><div id="data-verification-container"><input type="checkbox" style="display: none;"><label id="data-verification-icon"><svg width="18px" height="18px" viewBox="0 0 18 18"><path d="M1,9 L1,3.5 C1,2 2,1 3.5,1 L14.5,1 C16,1 17,2 17,3.5 L17,14.5 C17,16 16,17 14.5,17 L3.5,17 C2,17 1,16 1,14.5 L1,9 Z"></path></path><polyline points="1 9 7 14 15 4"></polyline></svg></label><p>I give my consent on collecting my email and IP address for the purpose of processing this request. For more check <a href="https://gdprcdn.b-cdn.net/pages/privacy_policy"  target="_blank">Privacy Policy</a>.</p></div></div></div>'';\r\n\r\n    var ccpaSendRequest = function(callback) {\r\n      $.ajax({\r\n        url: ''https://www.cloudflare.com/cdn-cgi/trace'',\r\n        method: ''GET'',\r\n        success: function(resp) {\r\n          if (!resp.error) {\r\n            let ipInfo = resp;\r\n            let ipRegex = /[0-9]{1,3}.[0-9]{1,3}.[0-9]{1,3}.[0-9]{1,3}/\r\n            let ipAddress = ipInfo.match(ipRegex)[0];\r\n\r\n            $.ajax({\r\n                url: ''https://gdpr.apps.isenselabs.com/gdprRequests/submitRequest'',\r\n                method: ''POST'',\r\n                data: {\r\n                    shop: Shopify.shop,\r\n                    email: email,\r\n                    type: type,\r\n                    sourceOfRequest: 2,\r\n                    ipAddress: ipAddress,\r\n                    consentGiven: consentGiven,\r\n                    lang: Shopify.locale ? Shopify.locale : '''',\r\n                    gtranslateLang: isenseGDPR.Cookies.get(''googtrans'') ? isenseGDPR.Cookies.get(''googtrans'') : ''''\r\n                },\r\n                success: function(resp) {\r\n                    if (!resp.error) {\r\n                        ccpaSlideUpAll();\r\n                        alert(''Your request has been submitted successfully. Please check your email for more information.'');\r\n                    } else {\r\n                        alert(resp.message);\r\n                    }\r\n                    if (typeof callback == ''function'') {\r\n                        callback(resp);\r\n                    }\r\n                }\r\n            });\r\n          } else {\r\n              alert(resp.message);\r\n          }\r\n        }\r\n      });\r\n    }\r\n\r\n    $(document).ready(function() {\r\n        let searchParams = new URLSearchParams(window.location.search);\r\n         let param = searchParams.get(''id'');\r\n         if(param) {\r\n             document.getElementById(param).scrollIntoView();\r\n         }\r\n\r\n      //Append modal to body, because otherwise it will not stay centered(even if position is fixed)\r\n      $("body").append(verificationModalContent);\r\n\r\n      // When the user clicks on <span> (x), close the modal\r\n      $(''.data-verification-close:first'').on(''click'', function(e) {\r\n          e.preventDefault();\r\n          closeVerificationModal();\r\n      });\r\n\r\n      $(''#data-verification-icon, #data-verification-container p'').on(''click'', function(e) {\r\n          e.preventDefault();\r\n\r\n          // Detect a href''s click, because it is overwritten.\r\n          if($(e.target).is("a")) {\r\n            window.open(e.target.href, ''_blank'');\r\n            return;\r\n          }\r\n\r\n          $(''#data-verification-icon'').addClass("clicked");\r\n          setTimeout(()=>{\r\n            $("#data-verification-modal").fadeOut();\r\n            $(''#data-verification-background .loading'').css(''display'', ''inline-block'');\r\n            consentGiven = true;\r\n            ccpaSendRequest(function(resp) {\r\n                consentGiven = false;\r\n                closeVerificationModal();\r\n            });\r\n          }, 400);\r\n      });\r\n    });\r\n\r\n    function openVerificationModal(){\r\n      $("#data-verification-modal").css("display", "block")\r\n      $(''#data-verification-background'').css("display", "block");\r\n    }\r\n    function closeVerificationModal(){\r\n      $(''#data-verification-background'').fadeOut();\r\n      $(''#data-verification-icon'').removeClass("clicked");\r\n      $(''#data-verification-background .loading'').css(''display'', ''none'');\r\n    }\r\n\r\n    $(''#btn-ccpa-edit-account-request'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        ccpaSlideUpAll();\r\n        $(''#form-ccpa-edit-account-request'').slideDown(200);\r\n        $(this).attr("aria-expanded", "true");\r\n    });\r\n\r\n    $(''#form-ccpa-edit-account-request form input[type=submit]'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        email = $(''#form-ccpa-edit-account-request form input[name=email]'').val();\r\n        type = ''customer/edit'';\r\n        openVerificationModal();\r\n    });\r\n\r\n    $(''#btn-ccpa-requests-request, #btn-ccpa-personal-information-request, #btn-ccpa-orders-request'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        ccpaSlideUpAll();\r\n\r\n        type = '''';\r\n\r\n        switch($(this).attr(''id'')) {\r\n            case ''btn-ccpa-requests-request'':\r\n                type = ''customer/requests'';\r\n                break;\r\n            case ''btn-ccpa-personal-information-request'':\r\n                type = ''customer/personal_info'';\r\n                break;\r\n            case ''btn-ccpa-orders-request'':\r\n                type = ''customer/orders'';\r\n                break;\r\n        }\r\n\r\n        $(''#form-ccpa-data-account-request form input[name="request_type"]'').val(type);\r\n\r\n        $(''#form-ccpa-data-account-request'').slideDown(200);\r\n        $(this).attr("aria-expanded", "true");\r\n    });\r\n\r\n    $(''#form-ccpa-data-account-request form input[type=submit]'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        email = $(''#form-ccpa-data-account-request form input[name=email]'').val();\r\n        type = $(''#form-ccpa-data-account-request form input[name="request_type"]'').val();\r\n        openVerificationModal();\r\n    });\r\n\r\n    $(''#btn-ccpa-personal-data-report-request'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        ccpaSlideUpAll();\r\n        $(''#form-ccpa-personal-data-report-request'').slideDown(200);\r\n        $(this).attr("aria-expanded", "true");\r\n    });\r\n\r\n    $(''#form-ccpa-personal-data-report-request form input[type=submit]'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        email = $(''#form-ccpa-personal-data-report-request form input[name=email]'').val();\r\n        type = ''customer/report'';\r\n        openVerificationModal();\r\n    });\r\n\r\n    $(''#btn-ccpa-do-not-sell-request'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        ccpaSlideUpAll();\r\n        $(''#form-ccpa-do-not-sell-request'').slideDown(200);\r\n        $(this).attr("aria-expanded", "true");\r\n    });\r\n\r\n    $(''#form-ccpa-do-not-sell-request form input[type=submit]'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        email = $(''#form-ccpa-do-not-sell-request form input[name=email]'').val();\r\n        type = ''customer/do-not-sell'';\r\n        openVerificationModal();\r\n    });\r\n\r\n    $(''#btn-ccpa-delete-account-request'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        ccpaSlideUpAll();\r\n        $(''#form-ccpa-delete-account-request'').slideDown(200);\r\n        $(this).attr("aria-expanded", "true");\r\n    });\r\n\r\n    $(''#form-ccpa-delete-account-request form input[type=submit]'').on(''click'', function(e) {\r\n        e.preventDefault();\r\n        email = $(''#form-ccpa-delete-account-request form input[name=email]'').val();\r\n        type = ''customer/delete'';\r\n        openVerificationModal();\r\n    });\r\n\r\n\r\n</script>\r\n','\r',char(13)),'\n',char(10)),NULL,'CCPA Compliance','#form-ccpa-edit-account-request, #form-ccpa-data-account-request, #form-ccpa-personal-data-report-request, #form-ccpa-delete-account-request , #form-ccpa-do-...',NULL,'published',1636491563,'default',NULL,0,1636491563,1636491563,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(7,'Clearly Calendula Sample Pack On Sale','clearly-calendula-sample-pack-on-sale','',NULL,'Clearly Calendula Sample Pack On Sale',NULL,NULL,'published',1638307799,'default',NULL,0,1638307799,1773009909,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(8,'Do not sell my personal information','ccpa-opt-out',replace('<link rel="stylesheet" type="text/css" href="https://cdn.shopify.com/shopifycloud/privacy-banner/data-sale-opt-out.css">\n<meta charset="utf-8"> <p>As described in our Privacy Policy, we collect personal information from your interactions with us and our website, including through cookies and similar technologies. We may also share this personal information with third parties, including advertising partners. We do this in order to show you ads on other websites that are more relevant to your interests and for other reasons outlined in our privacy policy.</p> <p>Sharing of personal information for targeted advertising based on your interaction on different websites may be considered "sales", "sharing", or "targeted advertising" under certain U.S. state privacy laws. Depending on where you live, you may have the right to opt out of these activities. If you would like to exercise this opt-out right, please follow the instructions below.</p> <p>If you visit our website with the Global Privacy Control opt-out preference signal enabled, depending on where you are, we will treat this as a request to opt-out of activity that may be considered a “sale” or “sharing” of personal information or other uses that may be considered targeted advertising for the device and browser you used to visit our website.</p>\n<div id="pc--optOutFormContainer" data-not-applicable=''To opt out of the "sale" or "sharing" of your personal information collected using cookies and other device-based identifiers as described above, you must be browsing from one of the applicable US states referred to above.'' data-form-description=''If you would like to opt out of activity that may be considered a "sale" or "share," or "targeted advertising", please submit your email.'' data-email-label="Email" data-success="Opted-out successfully" data-error="A problem occurred, try submitting your email again&gt;"></div>\n<script src="https://cdn.shopify.com/shopifycloud/privacy-banner/data-sale-opt-out.js" defer></script> <script src="https://js.hcaptcha.com/1/api.js?onload=optOutOnLoad" defer></script>\n\n','\n',char(10)),NULL,'Do not sell my personal information','As described in our Privacy Policy, we collect personal information from your interactions with us and our website, including through cookies and similar tec...',NULL,'published',1645730787,'default',NULL,0,1645730787,1726522358,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(9,'FAQ','faq',replace('<p><strong>Are Your Teas Organic?</strong></p>\n<p>All of our teas are certified Organic by the USDA! We feel that organic ingredients are important for health and wellness and our planet.</p>\n<p> </p>\n<p><strong>Do Your Teas Have </strong><b>Caffeine?</b></p>\n<p>Some of our blends have natural caffeine from the tea leaves.  Black tea based blends, like our Clearly Calendula Morning blend have approximately 40-50 mg of caffeine, which is about half that of a cup of coffee.  Green tea based blends, like our Clearly Calendula Afternoon blend have approximately 20-30 mg of caffeine.  Our herbal blends, like our Clearly Calendula Evening blend are caffeine free and an excellent choice for drinking before bed, or if you are avoiding caffeine.  Caffeine from tea often is absorbed more slowly than from coffee or energy drinks, due to the tannins in the tea (these tannins also have cancer fighting properties), so you tend to get less of a caffeine rush and crash, and more of a gradual energy that lasts longer.</p>\n<p> </p>\n<p><strong>Can I Drink Your Teas If I Am Pregnant?</strong></p>\n<p>Great question!  You should absolutely talk with your doctor about what is safe to eat and drink while pregnant.  In general pregnant people are advised to avoid consuming more than 200 mg of caffeine per day.  </p>\n<p>The amazing Calendula Flower, used in our anti-acne teas, is something you should avoid if pregnant.  While there are no clear studies on it, there are concerns about Calendula and it is considered "Likely Unsafe" for pregnant people by the NIH.  </p>\n<p> </p>\n<p><strong>Are Your Teas Just For Women?</strong></p>\n<p>Not at all!  Anyone can enjoy our teas and get the benefits, regardless of age or gender.  </p>\n<p> </p>\n<p> </p>','\n',char(10)),NULL,'FAQ','Are Your Teas Organic? All of our teas are certified Organic by the USDA! We feel that organic ingredients are important for health and wellness and our plan...',NULL,'published',1621192182,'default',NULL,0,1621192182,1621192182,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(10,'GDPR Compliance','gdpr-compliance',replace('<style>\n    #form-gdpr-edit-account-request,\n    #form-gdpr-data-account-request,\n    #form-gdpr-personal-data-report-request,\n    #form-gdpr-delete-account-request {\n        display: none;\n    }\n    #gdpr_page button {\n      background-color: transparent;\n      border: 0;\n      border-bottom: 1px solid black;\n      padding: 0px;\n    }\n\n    /* Modal background */\n    #data-verification-background {\n      display: none;\n      position: fixed;\n      z-index: 1;\n      padding-top: calc(50vh - 83px);\n      left: 0;\n      top: 0;\n      width: 100%;\n      height: 100%;\n      overflow: auto;\n      background-color: rgb(0,0,0);\n      background-color: rgba(0,0,0,0.4);\n      opacity: unset;\n      z-index: 9999;\n    }\n    /* Modal Content */\n    #data-verification-modal {\n      background-color: #fefefe;\n      margin: auto;\n      padding: 16px;\n      border: 1px solid #888;\n      width: 38%;\n    }\n    /* Modal Close Button */\n    .data-verification-close {\n      color: #aaaaaa;\n      float: right;\n      font-size: 28px;\n      font-weight: bold;\n      line-height: 17px;\n    }\n    .data-verification-close:hover,\n    .data-verification-close:focus {\n      color: #000;\n      text-decoration: none;\n      cursor: pointer;\n    }\n    /* Checkbox Text */\n    #data-verification-container p{\n      display: inline-block;\n      padding-left: 5px;\n      vertical-align: top;\n      width: calc(100% - 45px);\n      cursor: pointer;\n    }\n    #data-verification-container a, #data-verification-container a:hover{\n      text-decoration: underline!important;\n      color: #4285f4;\n    }\n    /* Checkbox Icon */\n    #data-verification-icon {\n      cursor: pointer;\n      position: relative;\n      margin: auto;\n      width: 18px;\n      height: 18px;\n      -webkit-tap-highlight-color: transparent;\n      transform: translate3d(0, 0, 0);\n      margin-top: 2px;\n    }\n    #data-verification-icon:before {\n      content: "";\n      position: absolute;\n      top: -7px;\n      left: -7px;\n      width: 32px;\n      height: 32px;\n      border-radius: 50%;\n      background: rgba(34,50,84,0.03);\n      opacity: 0;\n      transition: opacity 0.2s ease;\n    }\n    #data-verification-icon svg {\n      position: relative;\n      z-index: 1;\n      fill: none;\n      stroke-linecap: round;\n      stroke-linejoin: round;\n      stroke: #c8ccd4;\n      stroke-width: 1.5;\n      transform: translate3d(0, 0, 0);\n      transition: all 0.2s ease;\n    }\n    #data-verification-icon svg path {\n      stroke-dasharray: 60;\n      stroke-dashoffset: 0;\n    }\n    #data-verification-icon svg polyline {\n      stroke-dasharray: 22;\n      stroke-dashoffset: 66;\n    }\n    #data-verification-icon:hover:before {\n      opacity: 1;\n    }\n    #data-verification-container:hover #data-verification-icon svg {\n      stroke: #4285f4;\n    }\n    #data-verification-icon.clicked svg {\n      stroke: #4285f4;\n    }\n    #data-verification-icon.clicked svg path {\n      stroke-dashoffset: 60;\n      transition: all 0.3s linear;\n    }\n    #data-verification-icon.clicked svg polyline {\n      stroke-dashoffset: 42;\n      transition: all 0.2s linear;\n      transition-delay: 0.15s;\n    }\n\n    /* Loading Element */\n    .loading {\n        display: none;\n        top:50vh;\n        left:50vw;\n        position:fixed;\n    }\n    .loading:not(:required):after {\n      content: '''';\n      display: block;\n      font-size: 10px;\n      width: 1em;\n      height: 1em;\n      margin-top: -0.5em;\n      -webkit-animation: spinner 1500ms infinite linear;\n      -moz-animation: spinner 1500ms infinite linear;\n      -ms-animation: spinner 1500ms infinite linear;\n      -o-animation: spinner 1500ms infinite linear;\n      animation: spinner 1500ms infinite linear;\n      border-radius: 0.5em;\n      -webkit-box-shadow: rgba(255,255,255, 1) 1.5em 0 0 0, rgba(255,255,255, 1) 1.1em 1.1em 0 0, rgba(255,255,255, 1) 0 1.5em 0 0, rgba(255,255,255, 1) -1.1em 1.1em 0 0, rgba(255,255,255, 1) -1.5em 0 0 0, rgba(255,255,255, 1) -1.1em -1.1em 0 0, rgba(255,255,255, 1) 0 -1.5em 0 0, rgba(255,255,255, 1) 1.1em -1.1em 0 0;\n      box-shadow: rgba(255,255,255, 1) 1.5em 0 0 0, rgba(255,255,255, 1) 1.1em 1.1em 0 0, rgba(255,255,255, 1) 0 1.5em 0 0, rgba(255,255,255, 1) -1.1em 1.1em 0 0, rgba(255,255,255, 1) -1.5em 0 0 0, rgba(255,255,255, 1) -1.1em -1.1em 0 0, rgba(255,255,255, 1) 0 -1.5em 0 0, rgba(255,255,255, 1) 1.1em -1.1em 0 0;\n    }\n\n    /* Modal changes on mobile resolution*/\n    @media only screen and (max-width: 600px) {\n      #data-verification-modal {\n        width: 90%;\n      }\n    }\n\n    /* Animation */\n    @-webkit-keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n    @-moz-keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n    @-o-keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n    @keyframes spinner {\n      0% {\n        -webkit-transform: rotate(0deg);\n        -moz-transform: rotate(0deg);\n        -ms-transform: rotate(0deg);\n        -o-transform: rotate(0deg);\n        transform: rotate(0deg);\n      }\n      100% {\n        -webkit-transform: rotate(360deg);\n        -moz-transform: rotate(360deg);\n        -ms-transform: rotate(360deg);\n        -o-transform: rotate(360deg);\n        transform: rotate(360deg);\n      }\n    }\n  </style>\n<div id="gdpr_page" class="col-sm-12">\n    <div class="text-center">\n        The app used for assuring the GDPR/CCPA compliance of this site, collects your IP and the email address in order to process the data. For more check <a href="https://gdprcdn.b-cdn.net/pages/privacy_policy" target="_blank"> Privacy Policy</a><a>\n    </a>\n</div>\n    <h2>Data Rectification</h2>\n    <p>You can use the link below to update your account data if it is not accurate.</p>\n    <ul class="list-unstyled">\n        <li><button id="btn-gdpr-edit-account-request" aria-label="edit your account information" aria-controls="form-gdpr-edit-account-request" aria-expanded="false">Edit your account information</button></li>\n    </ul>\n    <div id="form-gdpr-edit-account-request">\n        <form>\n            <label for="form-gdpr-edit-account-request-email">Enter your email to confirm your identity</label>\n            <input type="email" name="email" id="form-gdpr-edit-account-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\n            <input type="submit" class="btn" value="Submit">\n        </form>\n    </div>\n    <h2>Data Portability</h2>\n    <p>You can use the links below to download all the data we store and use for a better experience in our store.</p>\n    <ul class="list-unstyled">\n      <li><button id="btn-gdpr-requests-request" aria-label="GDPR requests" aria-controls="form-gdpr-data-account-request" aria-expanded="false">GDPR requests</button></li>\n      <li><button id="btn-gdpr-personal-information-request" aria-label="personal information" aria-controls="form-gdpr-data-account-request" aria-expanded="false">Personal information</button></li>\n      <li><button id="btn-gdpr-orders-request" aria-label="orders" aria-controls="form-gdpr-data-account-request" aria-expanded="false">Orders</button></li>\n    </ul>\n    <div id="form-gdpr-data-account-request">\n        <form>\n            <label for="form-gdpr-data-account-request-email">Enter your email to confirm your identity</label>\n            <input type="email" name="email" id="form-gdpr-data-account-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\n            <input type="submit" class="btn" value="Submit">\n            <input type="hidden" name="request_type" value="">\n        </form>\n    </div>\n    <h2>Access to Personal Data</h2>\n    <p>You can use the link below to request a report which will contain all personal information that we store for you.</p>\n    <ul class="list-unstyled">\n      <li><button id="btn-gdpr-personal-data-report-request" aria-label="request a report" aria-controls="form-gdpr-personal-data-report-request" aria-expanded="false">Request a report</button></li>\n    </ul>\n    <div id="form-gdpr-personal-data-report-request">\n        <form>\n            <label for="form-gdpr-personal-data-report-request-email">Enter your email to confirm your identity</label>\n            <input type="email" name="email" id="form-gdpr-personal-data-report-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\n            <input type="submit" class="btn" value="Submit">\n        </form>\n    </div>\n    <h2>Right to be Forgotten</h2>\n    <p>Use this option if you want to remove your personal and other data from our store. Keep in mind that <strong>this process will delete your account, so you will no longer be able to access or use it anymore</strong>.</p>\n    <ul class="list-unstyled">\n      <li><button id="btn-gdpr-delete-account-request" aria-label="request personal data deletion" aria-controls="form-gdpr-delete-account-request" aria-expanded="false">Request personal data deletion</button></li>\n    </ul>\n    <div id="form-gdpr-delete-account-request">\n        <form>\n            <label for="form-gdpr-delete-account-request-email">Enter your email to confirm your identity</label>\n            <input type="email" name="email" id="form-gdpr-delete-account-request-email" placeholder="example@email.com" autocomplete="email" autocorrect="off" autocapitalize="off" autofocus="">\n            <input type="submit" class="btn" value="Submit">\n        </form>\n    </div>\n</div>\n\n<script src="https://code.jquery.com/jquery-2.2.4.min.js" integrity="sha256-BbhdlvQf/xTY9gja0Dq3HiwQF8LaCRTXxZKRutelT44=" crossorigin="anonymous"></script>\n\n<script>\n    var gdprSlideUpAll = function() {\n        $(''#form-gdpr-edit-account-request'').slideUp(100);\n        $(''#form-gdpr-data-account-request'').slideUp(100);\n        $(''#form-gdpr-personal-data-report-request'').slideUp(100);\n        $(''#form-gdpr-delete-account-request'').slideUp(100);\n        $(''#gdpr_page button'').attr("aria-expanded", "false");\n    };\n\n    var email, type, consentGiven = false;\n    var verificationModalContent = ''<div id="data-verification-background"><div class="loading"></div><div id="data-verification-modal"><span class="data-verification-close">&times;</span><div id="data-verification-container"><input type="checkbox" style="display: none;"><label id="data-verification-icon"><svg width="18px" height="18px" viewBox="0 0 18 18"><path d="M1,9 L1,3.5 C1,2 2,1 3.5,1 L14.5,1 C16,1 17,2 17,3.5 L17,14.5 C17,16 16,17 14.5,17 L3.5,17 C2,17 1,16 1,14.5 L1,9 Z"></path></path><polyline points="1 9 7 14 15 4"></polyline></svg></label><p>I give my consent on collecting my email and IP address for the purpose of processing this request. For more check <a href="https://gdprcdn.b-cdn.net/pages/privacy_policy"  target="_blank">Privacy Policy</a>.</p></div></div></div>'';\n\n    var gdprSendRequest = function(callback) {\n      $.ajax({\n        url: ''https://www.cloudflare.com/cdn-cgi/trace'',\n        method: ''GET'',\n        success: function(resp) {\n          if (!resp.error) {\n            let ipInfo = resp;\n            let ipRegex = /[0-9]{1,3}.[0-9]{1,3}.[0-9]{1,3}.[0-9]{1,3}/\n            let ipAddress = ipInfo.match(ipRegex)[0];\n\n            $.ajax({\n                url: ''https://gdpr.apps.isenselabs.com/gdprRequests/submitRequest'',\n                method: ''POST'',\n                data: {\n                    shop: Shopify.shop,\n                    email: email,\n                    type: type,\n                    sourceOfRequest: 1,\n                    ipAddress: ipAddress,\n                    consentGiven: consentGiven,\n                    lang: Shopify.locale ? Shopify.locale : '''',\n                    gtranslateLang: isenseGDPR.Cookies.get(''googtrans'') ? isenseGDPR.Cookies.get(''googtrans'') : ''''\n                },\n                success: function(resp) {\n                    if (!resp.error) {\n                        gdprSlideUpAll();\n                        alert(''Your request has been submitted successfully. Please check your email for more information.'');\n                    } else {\n                        alert(resp.message);\n                    }\n                    if (typeof callback == ''function'') {\n                        callback(resp);\n                    }\n                }\n            });\n          } else {\n              alert(resp.message);\n          }\n        }\n      });\n    }\n\n    $(document).ready(function() {\n      //Append modal to body, because otherwise it will not stay centered(even if position is fixed)\n      $("body").append(verificationModalContent);\n\n      // When the user clicks on <span> (x), close the modal\n      $(''.data-verification-close:first'').on(''click'', function(e) {\n          e.preventDefault();\n          closeVerificationModal();\n      });\n\n      $(''#data-verification-icon, #data-verification-container p'').on(''click'', function(e) {\n          e.preventDefault();\n\n          // Detect a href''s click, because it is overwritten.\n          if($(e.target).is("a")) {\n            window.open(e.target.href, ''_blank'');\n            return;\n          }\n\n          $(''#data-verification-icon'').addClass("clicked");\n          setTimeout(()=>{\n            $("#data-verification-modal").fadeOut();\n            $(''#data-verification-background .loading'').css(''display'', ''inline-block'');\n            consentGiven = true;\n            gdprSendRequest(function(resp) {\n                consentGiven = false;\n                closeVerificationModal();\n            });\n          }, 400);\n      });\n    });\n\n    function openVerificationModal(){\n      $("#data-verification-modal").css("display", "block")\n      $(''#data-verification-background'').css("display", "block");\n    }\n    function closeVerificationModal(){\n      $(''#data-verification-background'').fadeOut();\n      $(''#data-verification-icon'').removeClass("clicked");\n      $(''#data-verification-background .loading'').css(''display'', ''none'');\n    }\n\n    $(''#btn-gdpr-edit-account-request'').on(''click'', function(e) {\n        e.preventDefault();\n        gdprSlideUpAll();\n        $(''#form-gdpr-edit-account-request'').slideDown(200);\n        $(this).attr("aria-expanded", "true");\n    });\n\n    $(''#form-gdpr-edit-account-request form input[type=submit]'').on(''click'', function(e) {\n        e.preventDefault();\n        email = $(''#form-gdpr-edit-account-request form input[name=email]'').val();\n        type = ''customer/edit'';\n        openVerificationModal();\n    });\n\n    $(''#btn-gdpr-requests-request, #btn-gdpr-personal-information-request, #btn-gdpr-orders-request'').on(''click'', function(e) {\n        e.preventDefault();\n        gdprSlideUpAll();\n\n        type = '''';\n\n        switch($(this).attr(''id'')) {\n            case ''btn-gdpr-requests-request'':\n                type = ''customer/requests'';\n                break;\n            case ''btn-gdpr-personal-information-request'':\n                type = ''customer/personal_info'';\n                break;\n            case ''btn-gdpr-orders-request'':\n                type = ''customer/orders'';\n                break;\n        }\n\n        $(''#form-gdpr-data-account-request form input[name="request_type"]'').val(type);\n\n        $(''#form-gdpr-data-account-request'').slideDown(200);\n        $(this).attr("aria-expanded", "true");\n    });\n\n    $(''#form-gdpr-data-account-request form input[type=submit]'').on(''click'', function(e) {\n        e.preventDefault();\n        email = $(''#form-gdpr-data-account-request form input[name=email]'').val();\n        type = $(''#form-gdpr-data-account-request form input[name="request_type"]'').val();\n        openVerificationModal();\n    });\n\n    $(''#btn-gdpr-personal-data-report-request'').on(''click'', function(e) {\n        e.preventDefault();\n        gdprSlideUpAll();\n        $(''#form-gdpr-personal-data-report-request'').slideDown(200);\n        $(this).attr("aria-expanded", "true");\n    });\n\n    $(''#form-gdpr-personal-data-report-request form input[type=submit]'').on(''click'', function(e) {\n        e.preventDefault();\n        email = $(''#form-gdpr-personal-data-report-request form input[name=email]'').val();\n        type = ''customer/report'';\n        openVerificationModal();\n    });\n\n    $(''#btn-gdpr-delete-account-request'').on(''click'', function(e) {\n        e.preventDefault();\n        gdprSlideUpAll();\n        $(''#form-gdpr-delete-account-request'').slideDown(200);\n        $(this).attr("aria-expanded", "true");\n    });\n\n    $(''#form-gdpr-delete-account-request form input[type=submit]'').on(''click'', function(e) {\n        e.preventDefault();\n        email = $(''#form-gdpr-delete-account-request form input[name=email]'').val();\n        type = ''customer/delete'';\n        openVerificationModal();\n    });\n  </script>\n','\n',char(10)),NULL,'GDPR Compliance','#form-gdpr-edit-account-request, #form-gdpr-data-account-request, #form-gdpr-personal-data-report-request, #form-gdpr-delete-account-request { display: none;...',NULL,'published',1636491562,'default',NULL,0,1636491562,1636491562,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(11,'Join Our Beautea Community','join-our-beautea-community',replace('<div style="display: none;"></div>\n<div style="display: none;"></div>\n<h2 style="text-align: center;">Please join our mailing list!</h2>\n<div style="text-align: center;"></div>\n<div style="text-align: center;">What you''ll get:</div>\n<div style="text-align: center;"></div>\n<h3 style="text-align: center;">Discounts!<br>Beauty Tips!<br>Fresh Product Drops!<br>More!</h3>\n<div style="text-align: center;"></div>\n<div style="text-align: center;"></div>\n<div style="text-align: center;">When you join you''ll get a discount code as a thank you. </div>\n<div style="text-align: center;"></div>\n<div style="text-align: center;">You can always unsubscribe if we ever bore you.</div>\n<p> </p>\n<div class="privy-embed-form" data-campaign="2539417"></div>','\n',char(10)),NULL,'Join Our Beautea Community','Please join our mailing list! What you''ll get: Discounts! Beauty Tips! Fresh Product Drops! More! When you join you''ll get a discount code as a thank you. Yo...',NULL,'published',1625329847,'default',NULL,0,1625329847,1625330067,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(12,'Maskne Treatment','maskne-treatment','',NULL,'Maskne Treatment',NULL,NULL,'published',1629135405,'default',NULL,0,1629135405,1773009912,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
INSERT OR REPLACE INTO "pages" ("id","title","slug","content","excerpt","meta_title","meta_description","meta_keywords","status","published_at","template","parent_id","sort_order","created_at","updated_at","created_by","updated_by","version","show_in_nav","nav_title","custom_css","custom_js","is_protected","required_roles") VALUES(13,'Subscriptions','subscriptions',replace('<div style="display: none;"></div>\n<div style="display: none;"></div>\n<p>The only thing better than drinking our tea, is drinking our tea every day!  In addition to tasting great, BeauTeas are functional teas.  This means that they are each carefully blended with ingredients designed to help your body in some way. </p>\n<div style="text-align: left;"></div>\n<p>Our organic herbs and flowers are much better for you than harsh chemicals, but they may take a little time to take effect.  We recommend drinking at least one cup of tea every day.  It''s even better if you can drink several cups of tea, as you''ll be getting more helpful plant based healing, and keeping hydrated.</p>\n<p>To help encourage you to drink tea every day, we offer Subscriptions for all of our teas.  Picking a Subscription means you''ll get your favorite tea delivered every month automatically.  To sweeten the (tea) pot, we offer <strong>a 10% Discount</strong> for Subscriptions.  </p>\n<p>Save more money, drink more tea, be more healthy!</p>\n<p>You can always change or cancel your subscription at anytime.  We don''t believe in lock-in.  </p>\n<p><img src="https://cdn.shopify.com/s/files/1/0554/7288/1831/files/85A6547_1024x1024.jpg?v=1625358249" width="1024x1024" height="1024x1024"></p>','\n',char(10)),NULL,'Subscriptions','The only thing better than drinking our tea, is drinking our tea every day! In addition to tasting great, BeauTeas are functional teas. This means that they ...',NULL,'published',1625358265,'default',NULL,0,1625358265,1632409562,NULL,NULL,1,0,NULL,NULL,NULL,0,NULL);
